declare(strict_types=1);
require_once dirname(__DIR__).'/includes/cms.php';exigirPermiso('newsletter.export');$estado=in_array($_GET['estado']??'',['activo','inactivo'],true)?(string)$_GET['estado']:'';$pdo=obtenerConexion();$sql='SELECT email,nombre,estado,origen,fecha_suscripcion,fecha_baja FROM newsletter_suscriptores'.($estado?' WHERE estado=:estado':'').' ORDER BY id';$q=$pdo->prepare($sql);$q->execute($estado?['estado'=>$estado]:[]);header('Content-Type:text/csv; charset=UTF-8');header('Content-Disposition:attachment; filename="newsletter-'.date('Ymd-His').'.csv"');$out=fopen('php://output','wb');fwrite($out,"\xEF\xBB\xBF");fputcsv($out,['Correo','Nombre','Estado','Origen','Fecha de suscripción','Fecha de baja']);while($r=$q->fetch())fputcsv($out,[$r['email'],$r['nombre'],$r['estado'],$r['origen'],$r['fecha_suscripcion'],$r['fecha_baja']]);fclose($out);
